// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  // Get weather icon emoji based on condition
  const getWeatherIcon = useCallback((condition: string): string => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloudy') || conditionLower.includes('cloud')) return '☁️';
    if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('snow')) return '❄️';
    if (conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
    if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
    return '🌡️';
  }, []);

  return {
    getWeatherIcon,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* HEADER */}
        <Stack gap={8} align="center">
          <Heading level={1}>{props.city} Weather</Heading>
           <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Current conditions and forecast
          </Text>
        </Stack>

        {/* CURRENT WEATHER CARD */}
        <Card shadow="md" padding={24} radius="lg">
          <Stack gap={20}>
            {/* Temperature section */}
            <Stack gap={12} align="center">
              <Icon name={state.getWeatherIcon(props.condition)} size={64} />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                {props.condition}
              </Text>
              <Heading level={1} color="var(--ggui-color-primary-600, #0284c7)" align="center">
                {props.temperature}°{props.unit}
              </Heading>
            </Stack>

            {/* Divider */}
            <Divider orientation="horizontal" margin={8} />

            {/* Details grid */}
            <Stack direction="horizontal" gap={16} justify="center" wrap>
              {/* Humidity */}
              <Stack gap={6} align="center">
                <Icon name="droplets" size={24} color="var(--ggui-color-primary-500, #0ea5e9)" />
                <Stack gap={2} align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                    Humidity
                  </Text>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)" align="center">
                    {props.humidity}%
                  </Text>
                </Stack>
              </Stack>

              {/* Wind Speed */}
              <Stack gap={6} align="center">
                <Icon name="wind" size={24} color="var(--ggui-color-success-500, #22c55e)" />
                <Stack gap={2} align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                    Wind
                  </Text>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)" align="center">
                    {props.windSpeed} {props.unit === 'C' ? 'm/s' : 'mph'}
                  </Text>
                </Stack>
              </Stack>
            </Stack>
          </Stack>
        </Card>

        {/* 5-DAY FORECAST */}
        {props.forecast && props.forecast.length > 0 && (
          <Card shadow="sm" padding={20} radius="lg">
            <Stack gap={16}>
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                5-Day Forecast
              </Heading>
              <Stack direction="horizontal" gap={12} wrap>
                {props.forecast.map((day, index) => (
                  <Card
                    key={index}
                    shadow="none"
                    border={true}
                    padding={12}
                    radius="md"
                    style={{ flex: '0 1 calc(20% - 10px)', minWidth: '100px' }}
                  >
                    <Stack gap={8} align="center">
                      {/* Day name */}
                      <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)" align="center">
                        {day.day}
                      </Text>

                      {/* Weather icon */}
                      <Icon name={state.getWeatherIcon(day.icon || '')} size={32} />

                      {/* High/Low temps */}
                      <Stack gap={4} align="center">
                        <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)" align="center">
                          {day.high}° / {day.low}°
                        </Text>
                      </Stack>
                    </Stack>
                  </Card>
                ))}
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for form steps
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation
  const isValidEmail = (value: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  };

  const nameError = currentStep >= 1 && !name.trim() ? 'Name is required' : '';
  const emailError = currentStep >= 1 && !isValidEmail(email) ? 'Valid email is required' : '';
  const step1Valid = name.trim() && isValidEmail(email);
  const step2Valid = satisfaction !== '';
  const step3Valid = features.length > 0;

  const canProceed = useCallback((): boolean => {
    if (currentStep === 1) return step1Valid;
    if (currentStep === 2) return step2Valid;
    if (currentStep === 3) return step3Valid;
    return true;
  }, [currentStep, step1Valid, step2Valid, step3Valid]);

  const handleNext = useCallback(() => {
    if (canProceed() && currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, canProceed]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments: comments.trim(),
    });
  }, [name, email, satisfaction, features, comments, submit]);

  const handleFeatureToggle = useCallback((feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  }, []);

  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: `${index + 1} - ${label}`,
  }));

  return {
    submit,
    currentStep,
    setCurrentStep,
    name,
    setName,
    email,
    setEmail,
    nameError,
    emailError,
    satisfaction,
    setSatisfaction,
    features,
    handleFeatureToggle,
    comments,
    setComments,
    canProceed,
    handleNext,
    handleBack,
    handleSubmit,
    satisfactionOptions,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const totalSteps = 4;
  const progressPercent = (state.currentStep / totalSteps) * 100;

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* HEADER */}
        <Stack gap={8}>
          <Heading level={1}>Multi-Step Survey</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {state.currentStep} of {totalSteps}
          </Text>
        </Stack>

        {/* PROGRESS BAR */}
        <Progress value={progressPercent} max={100} size="md" variant="default" />

        {/* CONTENT */}
        <Card shadow="md" padding={24}>
          <Stack gap={20}>
            {/* STEP 1: Name & Email */}
            {state.currentStep === 1 && (
              <Stack gap={16}>
                <Heading level={3}>Tell us about yourself</Heading>
                <Input
                  label="Name"
                  value={state.name}
                  onChange={state.setName}
                  placeholder="John Doe"
                  error={state.nameError}
                  required
                />
                <Input
                  label="Email"
                  type="email"
                  value={state.email}
                  onChange={state.setEmail}
                  placeholder="john@example.com"
                  error={state.emailError}
                  required
                />
              </Stack>
            )}

            {/* STEP 2: Satisfaction Rating */}
            {state.currentStep === 2 && (
              <Stack gap={16}>
                <Heading level={3}>How satisfied are you?</Heading>
                <RadioGroup
                  label="Satisfaction Rating"
                  value={state.satisfaction}
                  onChange={state.setSatisfaction}
                  options={state.satisfactionOptions}
                  direction="vertical"
                />
              </Stack>
            )}

            {/* STEP 3: Feature Interests */}
            {state.currentStep === 3 && (
              <Stack gap={16}>
                <Heading level={3}>Which features interest you?</Heading>
                <Stack gap={12}>
                  {props.featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={state.features.includes(feature)}
                      onChange={() => state.handleFeatureToggle(feature)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {/* STEP 4: Comments & Review */}
            {state.currentStep === 4 && (
              <Stack gap={16}>
                <Heading level={3}>Additional Comments</Heading>
                <TextArea
                  label="Comments"
                  value={state.comments}
                  onChange={state.setComments}
                  placeholder="Any additional feedback or comments..."
                  rows={6}
                  maxLength={500}
                  showCount
                />

                {/* REVIEW SECTION */}
                <Divider margin={16} />
                <Stack gap={12}>
                  <Heading level={4}>Review Your Answers</Heading>
                    <Box paddingX={16} paddingY={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8}>
                      <Stack gap={12}>
                        <Row justify="between" align="center">
                          <Text variant="label">Name:</Text>
                          <Text variant="body">{state.name}</Text>
                        </Row>
                        <Row justify="between" align="center">
                          <Text variant="label">Email:</Text>
                          <Text variant="body">{state.email}</Text>
                        </Row>
                        <Row justify="between" align="center">
                          <Text variant="label">Satisfaction:</Text>
                          <Text variant="body">
                            {state.satisfactionOptions.find((o) => o.value === state.satisfaction)?.label || 'N/A'}
                          </Text>
                        </Row>
                        <Row justify="between" align="start">
                          <Text variant="label">Features:</Text>
                          <Stack direction="horizontal" gap={8}>
                            {state.features.map((f) => (
                              <Badge key={f} variant="primary" size="sm">
                                {f}
                              </Badge>
                            ))}
                          </Stack>
                        </Row>
                        {state.comments && (
                          <Row justify="between" align="start">
                            <Text variant="label">Comments:</Text>
                            <Text variant="bodySmall" style={{ maxWidth: '400px' }}>
                              {state.comments}
                            </Text>
                          </Row>
                        )}
                      </Stack>
                    </Box>
                </Stack>
              </Stack>
            )}
          </Stack>
        </Card>

        {/* NAVIGATION BUTTONS */}
        <Row gap={12} justify="between">
          <Button
            variant="ghost"
            onClick={state.handleBack}
            disabled={state.currentStep === 1}
          >
            Back
          </Button>

          {state.currentStep < 4 && (
            <Button
              variant="primary"
              onClick={state.handleNext}
              disabled={!state.canProceed()}
            >
              Next
            </Button>
          )}

          {state.currentStep === 4 && (
            <Button
              variant="primary"
              onClick={state.handleSubmit}
            >
              Submit Survey
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state for tasks and UI
  const [tasks, setTasks] = useState(props.tasks || []);
  const [addingTaskColumn, setAddingTaskColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTaskTitle, setEditingTaskTitle] = useState('');

  // Sync incoming stream updates with local tasks
  React.useEffect(() => {
    if (taskChanged.latest?.task) {
      const updated = taskChanged.latest.task;
      if (taskChanged.latest.action === 'delete') {
        setTasks(prev => prev.filter(t => t.id !== updated.id));
      } else {
        setTasks(prev => {
          const exists = prev.find(t => t.id === updated.id);
          if (exists) {
            return prev.map(t => (t.id === updated.id ? { ...t, ...updated } : t));
          } else {
            return [...prev, updated];
          }
        });
      }
    }
  }, [taskChanged.latest]);

  // Computed: tasks by column
  const tasksByColumn = useCallback(() => {
    const map: Record<string, typeof tasks> = {};
    (props.columns || []).forEach(col => {
      map[col.id || ''] = [];
    });
    tasks.forEach(task => {
      const col = task.column || 'todo';
      if (!map[col]) map[col] = [];
      map[col].push(task);
    });
    return map;
  }, [tasks, props.columns]);

  // Computed: summary stats
  const stats = useCallback(() => {
    const total = tasks.length;
    const done = tasks.filter(t => t.column === 'done').length;
    return { total, done };
  }, [tasks]);

  // Add a new task to a column
  const handleAddTask = useCallback((columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const taskId = `task-${Date.now()}`;
    const newTask = {
      id: taskId,
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: '',
      column: columnId,
      dueDate: '',
    };
    setTasks(prev => [...prev, newTask]);
    taskUpdate({ action: 'create', taskId, data: { column: columnId } });
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingTaskColumn(null);
  }, [newTaskTitle, newTaskPriority, taskUpdate]);

  // Move a task to another column
  const handleMoveTask = useCallback((taskId: string, newColumn: string) => {
    setTasks(prev => prev.map(t => (t.id === taskId ? { ...t, column: newColumn } : t)));
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
  }, [taskUpdate]);

  // Edit a task title
  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    if (!newTitle.trim()) return;
    setTasks(prev => prev.map(t => (t.id === taskId ? { ...t, title: newTitle } : t)));
    taskUpdate({ action: 'edit', taskId, data: { column: tasks.find(t => t.id === taskId)?.column || 'todo' } });
    setEditingTaskId(null);
    setEditingTaskTitle('');
  }, [tasks, taskUpdate]);

  // Start editing a task
  const startEditTask = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTaskTitle(currentTitle);
  }, []);

  return {
    tasks,
    tasksByColumn,
    stats,
    addingTaskColumn,
    setAddingTaskColumn,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    editingTaskId,
    editingTaskTitle,
    setEditingTaskTitle,
    handleAddTask,
    handleMoveTask,
    handleEditTask,
    startEditTask,
    taskUpdate,
    taskChanged,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);
  const columns = props.columns || [];
  const tasksByCol = state.tasksByColumn();
  const { total, done } = state.stats();

  // Helper: get priority color
  const getPriorityColor = (priority?: string): 'primary' | 'warning' | 'error' => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'primary';
  };

  // Helper: get avatar initials
  const getInitials = (assignee?: string) => {
    if (!assignee) return '?';
    return assignee.substring(0, 2).toUpperCase();
  };

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* SUMMARY BAR */}
        <Card shadow="md" padding={16}>
          <Stack direction="horizontal" gap={32} align="center">
            <Stack direction="horizontal" gap={16} align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Total Tasks:</Text>
              <Heading level={4} color="var(--ggui-color-primary-600, #0284c7)">{total}</Heading>
            </Stack>
            <Divider orientation="vertical" margin={0} />
            <Stack direction="horizontal" gap={16} align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Completed:</Text>
              <Heading level={4} color="var(--ggui-color-success-600, #16a34a)">{done}</Heading>
            </Stack>
          </Stack>
        </Card>

        {/* KANBAN BOARD */}
        <Stack gap={20} align="start" direction="horizontal">
          {columns.map((column) => {
            const colId = column.id || '';
            const colTasks = tasksByCol[colId] || [];

            return (
              <Box
                key={colId}
                padding={16}
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius={8}
                style={{ flex: '1 1 0', minWidth: '280px' }}
              >
                <Stack gap={12}>
                  {/* COLUMN HEADER */}
                  <Stack direction="horizontal" gap={8} align="center" justify="between">
                    <Heading level={4}>{column.name}</Heading>
                    <Badge variant="secondary" size="sm">
                      {colTasks.length}
                    </Badge>
                  </Stack>

                  <Divider margin={8} />

                  {/* TASK CARDS */}
                  <Stack gap={12}>
                    {colTasks.map((task) => (
                      <Card
                        key={task.id}
                        shadow="sm"
                        padding={12}
                        radius="md"
                        background="var(--ggui-color-surface, #ffffff)"
                      >
                        <Stack gap={8}>
                          {/* TITLE / EDIT */}
                          {state.editingTaskId === task.id ? (
                            <Stack direction="horizontal" gap={8}>
                              <Input
                                label="Task title"
                                value={state.editingTaskTitle}
                                onChange={state.setEditingTaskTitle}
                                placeholder="Task title"
                                size="sm"
                              />
                              <Button
                                size="sm"
                                variant="primary"
                                onClick={() =>
                                  state.handleEditTask(task.id || '', state.editingTaskTitle)
                                }
                              >
                                Save
                              </Button>
                            </Stack>
                          ) : (
                            <Stack direction="horizontal" gap={8} align="center" justify="between">
                              <Text
                                variant="body"
                                truncate
                                color="var(--ggui-color-onSurface, #18181b)"
                              >
                                {task.title}
                              </Text>
                              <Button
                                size="xs"
                                variant="ghost"
                                onClick={() => state.startEditTask(task.id || '', task.title || '')}
                              >
                                <Icon name="edit" size={14} />
                              </Button>
                            </Stack>
                          )}

                          {/* PRIORITY BADGE */}
                          <Badge variant={getPriorityColor(task.priority)} size="sm" pill>
                            {task.priority || 'medium'}
                          </Badge>

                          {/* ASSIGNEE + DUE DATE ROW */}
                          <Stack direction="horizontal" gap={12} align="center">
                            {task.assignee && (
                              <Avatar name={task.assignee} size="sm" shape="circle" />
                            )}
                            {task.dueDate && (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                {new Date(task.dueDate).toLocaleDateString()}
                              </Text>
                            )}
                          </Stack>

                          {/* MOVE DROPDOWN */}
                          <Select
                            label="Move to column"
                            value={task.column || colId}
