// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  const filteredElements = useMemo(() => {
    if (!props.elements || props.elements.length === 0) return [];
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter((el) => {
      const name = (el.name || '').toLowerCase();
      const symbol = (el.symbol || '').toLowerCase();
      return name.includes(query) || symbol.includes(query);
    });
  }, [searchQuery, props.elements]);

  const categories = useMemo(() => {
    const cats = new Set<string>();
    if (props.elements && props.elements.length > 0) {
      props.elements.forEach((el) => {
        if (el.category) cats.add(el.category);
      });
    }
    return Array.from(cats).sort();
  }, [props.elements]);

  const categoryColors: Record<string, string> = {
    'alkali-metal': 'var(--ggui-color-warning-100, #fef3c7)',
    'alkaline-earth-metal': 'var(--ggui-color-warning-50, #fffbeb)',
    'lanthanide': 'var(--ggui-color-info-100, #cffafe)',
    'actinide': 'var(--ggui-color-primary-100, #e0f2fe)',
    'transition-metal': 'var(--ggui-color-primary-50, #f0f9ff)',
    'post-transition-metal': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    'metalloid': 'var(--ggui-color-outline, #d4d4d8)',
    'nonmetal': 'var(--ggui-color-success-50, #f0fdf4)',
    'halogen': 'var(--ggui-color-error-50, #fef2f2)',
    'noble-gas': 'var(--ggui-color-primary-200, #bae6fd)',
  };

  const getCategoryColor = (category?: string): string => {
    if (!category) return 'var(--ggui-color-surface, #ffffff)';
    const normalizedCategory = category.toLowerCase().replace(/\s+/g, '-');
    return categoryColors[normalizedCategory] || 'var(--ggui-color-surface, #ffffff)';
  };

  return { searchQuery, setSearchQuery, selectedElement, setSelectedElement, filteredElements, categories, getCategoryColor };
}

