// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State management
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Computed values
  const isOutOfStock = !props.product.stock || props.product.stock <= 0;
  const isLowStock = props.product.stock && props.product.stock < 10;
  const stockStatus = isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock';
  const stockVariant = isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success';
  const formattedPrice = props.product.price ? `${props.product.currency || '$'}${props.product.price.toFixed(2)}` : 'N/A';
  const maxQuantity = props.product.stock || 1;

  // Handlers
  const handleIncrement = useCallback(() => {
    setQuantity(q => (q < maxQuantity ? q + 1 : q));
  }, [maxQuantity]);

  const handleDecrement = useCallback(() => {
    setQuantity(q => (q > 1 ? q - 1 : 1));
  }, []);

  const handleAddToCart = useCallback(() => {
    if (props.product.id && !isOutOfStock) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, isOutOfStock, addToCart]);

  return { quantity, setQuantity, activeTab, setActiveTab, isOutOfStock, stockStatus, stockVariant, formattedPrice, maxQuantity, handleIncrement, handleDecrement, handleAddToCart };
}

