import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [inputText, setInputText] = useState('');
  const [allMessages, setAllMessages] = useState(props.messages);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-append new messages from stream
  React.useEffect(() => {
    if (message.latest) {
      setAllMessages(prev => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Manage typing indicator state
  React.useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active && typing.latest.sender) {
        setTypingUsers(prev => new Set(prev).add(typing.latest!.sender!));
      } else if (!typing.latest.active && typing.latest.sender) {
        setTypingUsers(prev => {
          const next = new Set(prev);
          next.delete(typing.latest!.sender!);
          return next;
        });
      }
    }
  }, [typing.latest]);

  // Auto-scroll to bottom on new messages
  React.useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [allMessages]);

  // Handle send message on Enter or button click
  const handleSend = useCallback(() => {
    if (inputText.trim()) {
      sendMessage({
        text: inputText,
        timestamp: new Date().toISOString(),
      });
      setInputText('');
    }
  }, [inputText, sendMessage]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  }, [handleSend]);

  return { sendMessage, message, typing, inputText, setInputText, allMessages, typingUsers, handleSend, handleKeyDown, messagesEndRef };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const formatTimestamp = (ts?: string) => {
    if (!ts) return '';
    const date = new Date(ts);
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={16} align="stretch">
        {/* HEADER */}
        <Card shadow="md" padding={16} radius="lg">
          <Stack direction="horizontal" justify="between" align="center">
            <Stack gap={8} align="start">
              <Heading level={2}>{props.title}</Heading>
            </Stack>
            <Badge variant="primary" size="md">{props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}</Badge>
          </Stack>
        </Card>

        {/* MESSAGE LIST */}
        <Card shadow="sm" padding={16} radius="lg" border={true} style={{ minHeight: '400px', maxHeight: '500px', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-4, 16px)' }}>
          {state.allMessages.length === 0 ? (
            <Text variant="body" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ marginTop: 'var(--ggui-spacing-8, 32px)' }}>
              No messages yet. Start the conversation!
            </Text>
          ) : (
            <>
              {state.allMessages.map((msg, idx) => {
                const isCurrentUser = msg.sender === props.currentUser;
                const prevSender = idx > 0 ? state.allMessages[idx - 1].sender : null;
                const showAvatar = msg.sender !== prevSender;

                return (
                  <Stack
                    key={idx}
                    direction="horizontal"
                    align="end"
                    justify={isCurrentUser ? 'end' : 'start'}
                    gap={8}
                    style={{ marginBottom: showAvatar ? 'var(--ggui-spacing-4, 16px)' : 'var(--ggui-spacing-1, 4px)' }}
                  >
                    {!isCurrentUser && showAvatar && (
                      <Avatar name={msg.sender || 'User'} size="sm" shape="circle" />
                    )}
                    {!isCurrentUser && !showAvatar && <Spacer size={32} />}
                    <Stack gap={2} align={isCurrentUser ? 'end' : 'start'} style={{ maxWidth: '60%' }}>
                      {showAvatar && !isCurrentUser && (
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{msg.sender || 'User'}</Text>
                      )}
                      <Box
                        padding={12}
                        background={isCurrentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                        borderRadius="var(--ggui-shape-radius-lg, 12px)"
                        style={{ wordWrap: 'break-word', overflowWrap: 'break-word' }}
                      >
                        <Text
                          variant="body"
                          color={isCurrentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                        >
                          {msg.text || ''}
                        </Text>
                      </Box>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" size="xs">
                        {formatTimestamp(msg.timestamp)}
                      </Text>
                    </Stack>
                  </Stack>
                );
              })}
              <div ref={state.messagesEndRef} />
            </>
          )}
        </Card>

        {/* TYPING INDICATOR */}
        {state.typingUsers.size > 0 && (
          <Box paddingX={16} paddingY={8}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ fontStyle: 'italic' }}>
              {Array.from(state.typingUsers).join(', ')} {state.typingUsers.size === 1 ? 'is' : 'are'} typing{' '}
              <Spinner size={12} color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ display: 'inline-block', marginLeft: '4px' }} />
            </Text>
          </Box>
        )}

        {/* INPUT AREA */}
        <Stack direction="horizontal" gap={8} align="end">
          <TextArea
            label="Message"
            value={state.inputText}
            onChange={state.setInputText}
            placeholder="Type your message..."
            rows={3}
            onKeyDown={state.handleKeyDown}
            style={{ display: 'none' }}
          />
          <textarea
            value={state.inputText}
            onChange={(e) => state.setInputText(e.target.value)}
            onKeyDown={state.handleKeyDown}
            placeholder="Type your message... (press Enter to send)"
            style={{
              flex: 1,
              padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              border: '1px solid var(--ggui-color-outline, #d4d4d8)',
              fontFamily: 'inherit',
              fontSize: 'var(--ggui-font-size-sm, 14px)',
              resize: 'vertical',
              minHeight: '44px',
              color: 'var(--ggui-color-onSurface, #18181b)',
              backgroundColor: 'var(--ggui-color-surface, #ffffff)',
            }}
          />
          <Button
            variant="primary"
            size="md"
            onClick={state.handleSend}
            disabled={!state.inputText.trim()}
            rightIcon={<Icon name="send" size={16} />}
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

