// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [flashingSymbols, setFlashingSymbols] = useState<Set<string>>(new Set());

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // Merge price updates into stocks when stream events arrive
  React.useEffect(() => {
    if (priceUpdate.latest) {
      const updated = priceUpdate.latest;
      setStocks((prev) => {
        const next = prev.map((s) =>
          s.symbol === updated.symbol
            ? { ...s, price: updated.price ?? s.price, change: updated.change ?? s.change, changePercent: updated.changePercent ?? s.changePercent }
            : s
        );
        // Flash the symbol that just updated
        if (updated.symbol) {
          setFlashingSymbols((prev) => new Set(prev).add(updated.symbol));
          setTimeout(() => {
            setFlashingSymbols((prev) => {
              const next = new Set(prev);
              next.delete(updated.symbol);
              return next;
            });
          }, 600); // Flash duration
        }
        return next;
      });
      setLastUpdated(new Date());
    }
  }, [priceUpdate.latest]);

  const formatPrice = useCallback((price?: number) => {
    return price?.toFixed(2) ?? '0.00';
  }, []);

  const formatChangePercent = useCallback((pct?: number) => {
    if (pct === undefined) return '0.00%';
    return `${pct > 0 ? '+' : ''}${pct.toFixed(2)}%`;
  }, []);

  const getChangeColor = useCallback((change?: number) => {
    if (change === undefined) return 'var(--ggui-color-onSurface, #18181b)';
    return change > 0
      ? 'var(--ggui-color-success-600, #16a34a)'
      : change < 0
      ? 'var(--ggui-color-error-600, #dc2626)'
      : 'var(--ggui-color-onSurface, #18181b)';
  }, []);

  return { stocks, lastUpdated, flashingSymbols, priceUpdate, marketStatus, formatPrice, formatChangePercent, getChangeColor };
}

export default function Component(props: Props) {
  const { stocks, lastUpdated, flashingSymbols, priceUpdate, marketStatus, formatPrice, formatChangePercent, getChangeColor } = useComponent(props);

  return (
    <Container maxWidth="4xl" padding={24}>
      <Stack gap={24}>
        {/* HEADER WITH TITLE AND LAST UPDATED */}
        <Stack gap={8}>
          <Row justify="between" align="center">
            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">Market Watch</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {lastUpdated.toLocaleTimeString()}
            </Text>
          </Row>
        </Stack>

        {/* STOCK CARDS GRID */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-4, 16px)',
          }}>
          {stocks.map((stock) => {
            const isFlashing = flashingSymbols.has(stock.symbol || '');
            const isPositive = (stock.change ?? 0) > 0;
            const isNegative = (stock.change ?? 0) < 0;

            return (
              <Card
                key={stock.symbol}
                padding={16}
                shadow="md"
                radius="lg"
                border={true}
                style={{
                  borderColor: isPositive
                    ? 'var(--ggui-color-success-200, #bbf7d0)'
                    : isNegative
                    ? 'var(--ggui-color-error-200, #fecaca)'
                    : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                  animation: isFlashing ? 'ggui-highlight 0.6s ease-in-out' : 'none',
                }}>
                <style>{`
                  @keyframes ggui-highlight {
                    0% { background-color: var(--ggui-color-surfaceVariant, #f4f4f5); }
                    50% { background-color: var(--ggui-color-primary-100, #e0f2fe); }
                    100% { background-color: var(--ggui-color-surfaceVariant, #f4f4f5); }
                  }
                `}</style>
                <Stack gap={12}>
                  {/* TICKER SYMBOL - LARGE & BOLD */}
                  <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">{stock.symbol}</Heading>

                  {/* COMPANY NAME */}
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{stock.name}</Text>

                  <Divider orientation="horizontal" margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

                  {/* PRICE */}
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text variant="body" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                      ${formatPrice(stock.price)}
                    </Text>
                  </Stack>

                  {/* CHANGE AMOUNT AND PERCENTAGE */}
                  <Stack direction="horizontal" gap={12} align="center">
                    <Text
                      variant="bodySmall"
                      weight="semibold"
                      color={getChangeColor(stock.change)}>
                      {stock.change !== undefined && stock.change > 0 ? '+' : ''}{stock.change?.toFixed(2)}
                    </Text>
                    <Row gap={4} align="center">
                      <Icon
                        name={isPositive ? 'trending-up' : isNegative ? 'trending-down' : 'minus'}
                        size={16}
                        color={getChangeColor(stock.change)}
                      />
                      <Text
                        variant="bodySmall"
                        weight="semibold"
                        color={getChangeColor(stock.change)}>
                        {formatChangePercent(stock.changePercent)}
                      </Text>
                    </Row>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </Box>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // State for wizard steps and form data
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name || '');
  const [email, setEmail] = useState(props.initialProfile?.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile?.avatar || props.avatarOptions?.[0] || '');
  const [role, setRole] = useState(props.initialProfile?.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile?.theme || 'light');

  // Validation
  const isValidEmail = useCallback((value: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  }, []);

  const isStep1Valid = useCallback(() => {
    return name.trim() !== '' && email.trim() !== '' && isValidEmail(email) && avatar !== '';
  }, [name, email, avatar, isValidEmail]);

  const isStep2Valid = useCallback(() => {
    return role !== '';
  }, [role]);

  const nameError = name.trim() === '' && currentStep === 1 ? 'Name is required' : '';
  const emailError = !isValidEmail(email) && email.trim() !== '' && currentStep === 1 ? 'Invalid email format' : email.trim() === '' && currentStep === 1 ? 'Email is required' : '';
  const roleError = role === '' && currentStep === 2 ? 'Role is required' : '';

  const handleNext = useCallback(() => {
    if (currentStep === 1 && isStep1Valid()) {
      setCurrentStep(2);
    } else if (currentStep === 2 && isStep2Valid()) {
      setCurrentStep(3);
    }
  }, [currentStep, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    complete({
      name,
      email,
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [name, email, avatar, role, emailNotifications, theme, complete]);

  return {
    currentStep,
    setCurrentStep,
    name,
    setName,
    email,
    setEmail,
    avatar,
    setAvatar,
    role,
    setRole,
    emailNotifications,
    setEmailNotifications,
    theme,
    setTheme,
    isStep1Valid,
    isStep2Valid,
    nameError,
    emailError,
    roleError,
    handleNext,
    handleBack,
    handleComplete,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  // Calculate progress
  const progress = (state.currentStep / 3) * 100;

  // Convert role options to SelectOption format
  const roleSelectOptions = props.roleOptions.map((r) => ({ value: r, label: r }));

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={32}>
        {/* STEP INDICATOR */}
        <Stack gap={8}>
          <Stack direction="horizontal" justify="center" align="center" gap={16}>
            {[1, 2, 3].map((step) => (
              <Stack key={step} align="center" gap={4}>
                <Box
                  padding={12}
                  borderRadius={9999}
                  background={
                    state.currentStep >= step
                      ? 'var(--ggui-color-primary-600, #0284c7)'
                      : 'var(--ggui-color-outlineVariant, #e4e4e7)'
                  }
                  style={{
                    minWidth: '40px',
                    minHeight: '40px',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                  }}
                >
                  <Text
                    color={
                      state.currentStep >= step
                        ? '#ffffff'
                        : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                    }
                    weight="semibold"
                    align="center"
                  >
                    {step}
                  </Text>
                </Box>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                  {step === 1 ? 'Profile' : step === 2 ? 'Preferences' : 'Review'}
                </Text>
              </Stack>
            ))}
          </Stack>
          <Progress value={progress} max={100} size="md" />
        </Stack>

        {/* STEP 1: PROFILE SETUP */}
        {state.currentStep === 1 && (
          <Card padding={32} shadow="md">
            <Stack gap={24}>
              <Heading level={2}>Profile Setup</Heading>
              <Stack gap={20}>
                {/* Name Input */}
                <Input
                  label="Full Name"
                  value={state.name}
                  onChange={state.setName}
                  placeholder="John Doe"
                  required
                  error={state.nameError}
                />

                {/* Email Input */}
                <Input
                  label="Email Address"
                  type="email"
                  value={state.email}
                  onChange={state.setEmail}
                  placeholder="you@example.com"
                  required
                  error={state.emailError}
                />

                {/* Avatar Selection */}
                <Stack gap={12}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Choose Avatar <Text is="span" color="var(--ggui-color-error-500, #ef4444)">*</Text>
                  </Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {props.avatarOptions.map((emoji) => (
                      <Box
                        key={emoji}
                        as={Clickable}
                        onClick={() => state.setAvatar(emoji)}
                        padding={12}
                        borderRadius={8}
                        background={
                          state.avatar === emoji
                            ? 'var(--ggui-color-primary-100, #e0f2fe)'
                            : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                        }
                        style={{
                          fontSize: '32px',
                          cursor: 'pointer',
                          transition: 'all var(--ggui-transition-colors, 200ms)',
                          border: state.avatar === emoji ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid transparent',
                        }}
                      >
                        {emoji}
                      </Box>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* STEP 2: PREFERENCES */}
        {state.currentStep === 2 && (
          <Card padding={32} shadow="md">
            <Stack gap={24}>
              <Heading level={2}>Preferences</Heading>
              <Stack gap={20}>
                {/* Role Selection */}
                <Select
                  label="Role"
                  value={state.role}
                  onChange={state.setRole}
                  options={roleSelectOptions}
                  placeholder="Select your role"
                  required
                  error={state.roleError}
                />

                <Divider />

                {/* Email Notifications Toggle */}
                <Toggle
                  label="Email Notifications"
                  checked={state.emailNotifications}
                  onChange={state.setEmailNotifications}
                  size="md"
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Receive email updates about your account activity
                </Text>

                <Divider />

                {/* Theme Preference */}
                <RadioGroup
                  label="Theme Preference"
                  value={state.theme}
                  onChange={state.setTheme}
                  options={[
                    { value: 'light', label: 'Light' },
                    { value: 'dark', label: 'Dark' },
                  ]}
                  direction="horizontal"
                />
              </Stack>
            </Stack>
          </Card>
        )}

        {/* STEP 3: REVIEW & CONFIRM */}
        {state.currentStep === 3 && (
          <Card padding={32} shadow="md">
            <Stack gap={24}>
              <Heading level={2}>Review Setup</Heading>
              <Stack gap={20}>
                {/* Profile Summary */}
                <Card padding={16} shadow="none" border={false} radius="md">
                  <Stack gap={12}>
                    <Text weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      PROFILE
                    </Text>
                    <Stack gap={8} direction="horizontal" align="center">
                      <Text style={{ fontSize: '24px' }}>{state.avatar}</Text>
                      <Stack gap={4}>
                        <Text weight="semibold">{state.name}</Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {state.email}
                        </Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Card>

                <Divider />

                {/* Preferences Summary */}
                <Card padding={16} shadow="none" border={false} radius="md">
                  <Stack gap={12}>
                    <Text weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      PREFERENCES
                    </Text>
                    <Stack gap={8}>
                      <Row justify="between">
                        <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Role:</Text>
                        <Text weight="semibold">{state.role}</Text>
                      </Row>
                      <Row justify="between">
                        <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Email Notifications:</Text>
                        <Badge variant={state.emailNotifications ? 'success' : 'default'}>
                          {state.emailNotifications ? 'Enabled' : 'Disabled'}
                        </Badge>
                      </Row>
                      <Row justify="between">
                        <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme:</Text>
                        <Text weight="semibold">{state.theme.charAt(0).toUpperCase() + state.theme.slice(1)}</Text>
                      </Row>
                    </Stack>
                  </Stack>
                </Card>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* NAVIGATION */}
        <Row gap={12} justify="between">
          <Button
            variant="ghost"
            onClick={state.handleBack}
            disabled={state.currentStep === 1}
          >
            {state.currentStep === 3 ? 'Go Back' : 'Back'}
          </Button>
          <Stack direction="horizontal" gap={12}>
            {state.currentStep < 3 && (
              <Button
                variant="primary"
                onClick={state.handleNext}
                disabled={
                  state.currentStep === 1
                    ? !state.isStep1Valid()
                    : state.currentStep === 2
                      ? !state.isStep2Valid()
                      : false
                }
              >
                Next
              </Button>
            )}
            {state.currentStep === 3 && (
              <Button variant="primary" onClick={state.handleComplete}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Row>
      </Stack>
    </Container>
  );
}
